const cfg = $input.first().json;
const [owner, repo] = String(cfg.githubRepo || 'n8n-io/n8n').split('/');
if (!owner || !repo) throw new Error('Set GITHUB_REPO as owner/repo');
const lookbackDays = Number(cfg.lookbackDays || 7);
const sinceDate = new Date(Date.now() - lookbackDays * 24 * 60 * 60 * 1000);
const since = sinceDate.toISOString();
const headers = {
  Accept: 'application/vnd.github+json',
  'User-Agent': 'n8n-free-lite-github-weekly-snapshot'
};
if (cfg.githubToken) headers.Authorization = `Bearer ${cfg.githubToken}`;
async function gh(path) {
  const response = await fetch(`https://api.github.com/repos/${owner}/${repo}${path}`, { headers });
  if (!response.ok) throw new Error(`GitHub ${path} failed: ${response.status} ${await response.text()}`);
  return response.json();
}
const commits = await gh(`/commits?since=${encodeURIComponent(since)}&per_page=30`);
const issues = await gh(`/issues?state=closed&since=${encodeURIComponent(since)}&per_page=30`);
const pulls = await gh(`/pulls?state=closed&sort=updated&direction=desc&per_page=30`);
const mergedPulls = pulls.filter(pr => pr.merged_at && new Date(pr.merged_at) >= sinceDate);
const issueOnly = issues.filter(item => !item.pull_request);
const lines = [];
lines.push(`# ${owner}/${repo} weekly snapshot`);
lines.push('');
lines.push(`Lookback: last ${lookbackDays} days since ${since}`);
lines.push('');
lines.push('## Counts');
lines.push(`- Commits: ${commits.length}`);
lines.push(`- Merged PRs: ${mergedPulls.length}`);
lines.push(`- Closed issues: ${issueOnly.length}`);
lines.push('');
lines.push('## Notable commits');
for (const commit of commits.slice(0, 10)) {
  const title = commit.commit?.message?.split('\n')[0] || 'Untitled commit';
  const author = commit.commit?.author?.name || 'unknown';
  lines.push(`- ${commit.sha.slice(0, 7)} ${title} — ${author}`);
}
if (!commits.length) lines.push('- None found.');
lines.push('');
lines.push('## Merged PRs');
for (const pr of mergedPulls.slice(0, 10)) lines.push(`- #${pr.number} ${pr.title}`);
if (!mergedPulls.length) lines.push('- None found.');
lines.push('');
lines.push('## Closed issues');
for (const issue of issueOnly.slice(0, 10)) lines.push(`- #${issue.number} ${issue.title}`);
if (!issueOnly.length) lines.push('- None found.');
lines.push('');
lines.push('---');
lines.push('Free lite workflow: no Claude API key and no Slack webhook required. Upgrade path: feed this snapshot into the full Claude weekly narrative workflow.');
return [{ json: { githubRepo: `${owner}/${repo}`, since, counts: { commits: commits.length, mergedPulls: mergedPulls.length, closedIssues: issueOnly.length }, markdown: lines.join('\n') } }];
